import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup, ZoomControl } from "react-leaflet";
import L from "leaflet";
import 'leaflet/dist/leaflet.css';
import BusTrendChart from "./BusTrendChart";

// Marker icons
const greenIcon = new L.Icon({
  iconUrl: "https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-green.png",
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const redIcon = new L.Icon({
  iconUrl: "https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png",
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  // Fetch bus data every 5 seconds
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();

        const now = Math.floor(Date.now() / 1000); // current unix timestamp in seconds

        // Add status based on last update
        const updatedBuses = data.map(bus => ({
          ...bus,
          status: now - bus.timestamp > 300 ? "ghost" : "active" // 5 minutes
        }));

        setBuses(updatedBuses);
      } catch (error) {
        console.error("Error fetching bus data:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div>
      {/* Button to toggle chart */}
      <div style={{ position: "absolute", top: 10, right: 10, zIndex: 1000 }}>
        <button
          onClick={() => setShowChart(!showChart)}
          style={{ padding: "10px 20px", backgroundColor: "#007bff", color: "white", border: "none", borderRadius: "5px" }}
        >
          {showChart ? "Hide Chart" : "Show Chart"}
        </button>
      </div>

      <MapContainer
        center={[40.7128, -74.006]}
        zoom={11}
        style={{ height: "100vh", width: "100%" }}
        scrollWheelZoom={true}
        zoomControl={false}
      >
        <ZoomControl position="topright" />
        <TileLayer
          url="https://cartodb-basemaps-a.global.ssl.fastly.net/light_all/{z}/{x}/{y}{r}.png"
          attribution=""
        />

        {buses.map(bus => (
          <Marker
            key={bus.id}
            position={[bus.lat, bus.lon]}
            icon={bus.status === "ghost" ? redIcon : greenIcon}
          >
            <Popup>
              Bus ID: {bus.id} <br />
              Status: {bus.status}
            </Popup>
          </Marker>
        ))}
      </MapContainer>

      {/* Show trend chart only when button clicked */}
      {showChart && <BusTrendChart buses={buses} />}
    </div>
  );
};

export default MapComponent;
